import{_ as e,o,c as a,ag as r}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"🌐 Web 安全与 CTF 入门指南","description":"","frontmatter":{"order":1},"headers":[],"relativePath":"ctf/WEB/intro.md","filePath":"ctf/WEB/intro.md","lastUpdated":1774465297000}'),l={name:"ctf/WEB/intro.md"};function i(s,t,n,c,d,p){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="🌐-web-安全与-ctf-入门指南" tabindex="-1">🌐 Web 安全与 CTF 入门指南 <a class="header-anchor" href="#🌐-web-安全与-ctf-入门指南" aria-label="Permalink to &quot;🌐 Web 安全与 CTF 入门指南&quot;">​</a></h1><p>在 CTF（夺旗赛）的所有方向中，Web 方向通常是最贴近实际业务场景，也是变化最多端的分支。本模块用于记录在各类靶场和比赛中遇到的 Web 题型、Bypass 技巧以及底层原理分析。</p><h2 id="🎯-核心技能树" tabindex="-1">🎯 核心技能树 <a class="header-anchor" href="#🎯-核心技能树" aria-label="Permalink to &quot;🎯 核心技能树&quot;">​</a></h2><p>要打好 Web CTF，不仅需要懂得如何“破坏”，更需要深刻理解应用是如何“构建”的：</p><ul><li><strong>HTTP 协议报文解析：</strong> Header 伪造、Chunked 编码走私、状态码利用。</li><li><strong>后端语言特性：</strong> * <code>PHP</code>：弱类型比较、伪协议、反序列化（POP 链）、无字母数字 RCE。 <ul><li><code>Java</code>：内存马注入、Shiro/Fastjson 反序列化、JNDI 注入。</li><li><code>Python</code>：SSTI 模板注入、Pickle 反序列化、沙箱逃逸。</li></ul></li><li><strong>经典漏洞模型：</strong> SQLi, XSS, SSRF, XXE, 文件上传与包含。</li></ul><h2 id="🧰-必备兵器库" tabindex="-1">🧰 必备兵器库 <a class="header-anchor" href="#🧰-必备兵器库" aria-label="Permalink to &quot;🧰 必备兵器库&quot;">​</a></h2><p>在实战演练中，熟练的工具链能节省大量的时间：</p><ol><li><strong>流量抓取与重放：</strong> Burp Suite (必备)</li><li><strong>目录与敏感文件扫描：</strong> dirsearch, ffuf</li><li><strong>自动化注入验证：</strong> SQLMap</li><li><strong>WebShell 管理：</strong> 蚁剑 (AntSword), 冰蝎 (Behinder), 哥斯拉 (Godzilla)</li></ol><div class="tip custom-block"><p class="custom-block-title">💡 学习建议</p><p>打 CTF 的核心不在于用工具一把梭，而在于<strong>编写属于自己的 PoC/Exp 脚本</strong>。遇到有意思的赛题，一定要复现并扒开源码分析底层逻辑。</p></div><hr><p><em>下一步：开始整理 <a href="./sqli.html">SQL 注入与 Bypass 技巧</a> 的实战笔记。</em></p>',11)])])}const _=e(l,[["render",i]]);export{u as __pageData,_ as default};
